import { ParticleField } from "@/components/ui/particle-field";

export default function ParticleHero() {
  return (
    <ParticleField className="h-[400px] rounded-2xl flex items-center justify-center" particleCount={80} particleColor="#6366f1">
      <div className="text-center space-y-3 relative z-10">
        <h1 className="text-5xl font-bold text-white">Particle Field</h1>
        <p className="text-neutral-400">Move your cursor to interact with the particles.</p>
      </div>
    </ParticleField>
  );
}

